    /// - File paths sanitized
    /// - Internal state not exposed
    /// - Generic "Internal error" message returned
    ///
    /// When disabled (development mode), full error details are returned.
    pub fn mask_error_details(self, enabled: bool) -> Self

    /// Configure based on environment
    /// Automatically masks in release builds or when FASTMCP_ENV=production
    pub fn auto_mask_errors(self) -> Self
