### Logging/Tracing Requirements

```rust
use tracing::{debug, warn, error, instrument};

impl Server {
    #[instrument(level = "debug", skip(self, error))]
    fn mask_and_log_error(&self, error: McpError, request_id: &RequestId) -> McpError {
        // Always log the full error server-side
        error!(
            request_id = %request_id,
            code = ?error.code,
            message = %error.message,
            data = ?error.data,
            "Handler error occurred"
        );

        if self.config.mask_error_details {
            debug!(
                request_id = %request_id,
                "Masking error details before sending to client"
            );
            let masked = error.masked(true);
            warn!(
                request_id = %request_id,
                original_message = %error.message,
                masked_message = %masked.message,
                "Error masked for client response"
            );
            masked
        } else {
            debug!(
                request_id = %request_id,
                "Sending full error details to client (masking disabled)"
            );
            error
        }
    }
}
```

Required trace points:
- `ERROR`: Full error logged server-side (always)
- `DEBUG`: Masking decision
- `WARN`: When masking changes error message significantly
- `DEBUG`: Configuration of masking setting

